-- {"operators": "INNER_JOIN,AGGREGATE,DISTINCT", "complexity": "high", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": true, "tables": "CUSTOMER,OORDER,ORDER_LINE", "ducklake": true}
SELECT c.C_W_ID, c.C_ID, c.C_LAST, COUNT(DISTINCT o.O_ID) AS orders, SUM(CASE WHEN ol.OL_DELIVERY_D IS NULL THEN ol.OL_AMOUNT ELSE 0 END) AS pending_amt, SUM(CASE WHEN ol.OL_DELIVERY_D IS NOT NULL THEN ol.OL_AMOUNT ELSE 0 END) AS delivered_amt FROM CUSTOMER c JOIN OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN ORDER_LINE ol ON o.O_W_ID = ol.OL_W_ID AND o.O_D_ID = ol.OL_D_ID AND o.O_ID = ol.OL_O_ID GROUP BY c.C_W_ID, c.C_ID, c.C_LAST;
